                merged_value = deep_merge_nodes(existing_value_node.value + value_node.value)
                merged_nodes[key] = MappingNode(tag=existing_value_node.tag, value=merged_value)
            else:
                # 非 MappingNode 冲突，保留最后一个值
                merged_nodes[key] = value_node
