import re
import sys

def split(s, platform='this'):

    if platform == 'this':
        platform = 1 if sys.platform != 'win32' else 0

    if platform == 1:
        # POSIX style
        pattern = re.compile(r)
    elif platform == 0:
        # Windows/CMD style
        pattern = re.compile(r)
    else:
        raise ValueError("Invalid platform value. Use 'this', 1 (POSIX), or 0 (Windows/CMD).")

    return pattern.findall(s)

